  1→@import './reset.css';
  2→@import './variables.css';
  3→
  4→html, body, #root {
  5→  height: 100%;
  6→  width: 100%;
  7→  overflow: hidden;
  8→}
  9→
 10→body {
 11→  font-family: var(--font-ui);
 12→  font-size: 13px;
 13→  color: var(--color-text-primary);
 14→  background: var(--color-background);
 15→  -webkit-font-smoothing: antialiased;
 16→  text-rendering: optimizeLegibility;
 17→}
 18→
 19→/* Custom scrollbars — light theme */
 20→::-webkit-scrollbar {
 21→  width: 6px;
 22→  height: 6px;
 23→}
 24→
 25→::-webkit-scrollbar-track {
 26→  background: transparent;
 27→}
 28→
 29→::-webkit-scrollbar-thumb {
 30→  background: rgba(0, 0, 0, 0.15);
 31→  border-radius: 3px;
 32→}
 33→
 34→::-webkit-scrollbar-thumb:hover {
 35→  background: rgba(0, 0, 0, 0.25);
 36→}
 37→
 38→/* Selection highlight */
 39→::selection {
 40→  background: rgba(26, 122, 104, 0.15);
 41→}
 42→
 43→/* Focus ring */
 44→:focus-visible {
 45→  outline: 2px solid var(--color-accent);
 46→  outline-offset: 1px;
 47→}
 48→
 49→/* Global input focus */
 50→input:not([readonly]):focus,
 51→select:focus {
 52→  border-color: var(--color-accent) !important;
 53→  box-shadow: 0 0 0 2px rgba(26, 122, 104, 0.15);
 54→  outline: none;
 55→}
 56→
 57→/* Modal animations */
 58→@keyframes modalOverlayIn {
 59→  from { opacity: 0; }
 60→  to { opacity: 1; }
 61→}
 62→
 63→@keyframes modalDialogIn {
 64→  from {
 65→    opacity: 0;
 66→    transform: scale(0.96) translateY(8px);
 67→  }
 68→  to {
 69→    opacity: 1;
 70→    transform: scale(1) translateY(0);
 71→  }
 72→}
 73→
 74→@keyframes fadeInUp {
 75→  from {
 76→    opacity: 0;
 77→    transform: translateY(4px);
 78→  }
 79→  to {
 80→    opacity: 1;
 81→    transform: translateY(0);
 82→  }
 83→}
 84→
 85→@keyframes pulse {
 86→  0%, 100% { opacity: 1; }
 87→  50% { opacity: 0.5; }
 88→}
 89→
 90→@keyframes warmPulse {
 91→  0%, 100% {
 92→    box-shadow: 0 0 6px rgba(45, 95, 142, 0.40);
 93→  }
 94→  50% {
 95→    box-shadow: 0 0 12px rgba(45, 95, 142, 0.60);
 96→  }
 97→}
 98→
 99→@keyframes toastSlideUp {
100→  from {
101→    opacity: 0;
102→    transform: translateY(8px);
103→  }
104→  to {
105→    opacity: 1;
106→    transform: translateY(0);
107→  }
108→}
109→
110→@keyframes toastCountdown {
111→  from { width: 100%; }
112→  to { width: 0%; }
113→}
