  1→import { useCallback, useEffect } from 'react';
  2→import { useEditor } from '@/app/EditorProvider';
  3→import { useProject } from '@/app/ProjectProvider';
  4→import { usePlanClipboardController } from '@/clipboard/usePlanClipboardController';
  5→import { TOOLS } from '@/editor/tools';
  6→import { detectRooms } from '@/geometry/roomDetection';
  7→import { createRoom } from '@/domain/models';
  8→import { isTypingTarget } from '@/utils/keyboard';
  9→import {
 10→  NewIcon, SaveIcon, LoadIcon, UndoIcon, RedoIcon,
 11→  CopyIcon, CutIcon, PasteIcon,
 12→  SelectIcon, DimensionIcon, WallIcon, BeamIcon, StairIcon,
 13→  TrussDrawIcon,
 14→  SectionCutIcon, SlabIcon, RoomIcon, DoorIcon, WindowIcon,
 15→  ColumnIcon, LandingIcon, RailingIcon,
 16→  ParapetIcon, DrainIcon, OpeningIcon,
 17→  KitchenTopIcon, ToiletIcon, LavatoryIcon, TableIcon, TVIcon, SofaIcon, BedIcon,
 18→  GridIcon, SnapIcon, DetectRoomsIcon,
 19→  SidebarIcon, PropertiesIcon,
 20→} from './ToolbarIcons';
 21→import { FIXTURE_TYPES } from '@/editor/tools';
 22→import Tooltip from './Tooltip';
 23→import styles from './Toolbar.module.css';
 24→
 25→const viewModes = [
 26→  { key: 'plan', label: 'Plan', viewMode: 'plan' },
 27→  { key: 'front', label: 'Front', viewMode: 'elevation_front' },
 28→  { key: 'rear', label: 'Rear', viewMode: 'elevation_rear' },
 29→  { key: 'left', label: 'Left', viewMode: 'elevation_left' },
 30→  { key: 'right', label: 'Right', viewMode: 'elevation_right' },
 31→  { key: 'section', label: 'Section', viewMode: 'section_view' },
 32→];
 33→
 34→const toolItems = [
 35→  { tool: TOOLS.SELECT, label: 'Select', shortcut: 'V', Icon: SelectIcon },
 36→  { tool: TOOLS.DIMENSION, label: 'Dimension', shortcut: 'M', Icon: DimensionIcon },
 37→  { tool: TOOLS.WALL, label: 'Wall', shortcut: 'W', Icon: WallIcon },
 38→  { tool: TOOLS.BEAM, label: 'Beam', shortcut: 'B', Icon: BeamIcon },
 39→  { tool: TOOLS.STAIR, label: 'Stair', shortcut: 'T', Icon: StairIcon },
 40→  { tool: TOOLS.SECTION, label: 'Section Cut', shortcut: 'Q', Icon: SectionCutIcon },
 41→  { tool: TOOLS.SLAB, label: 'Slab', shortcut: 'S', Icon: SlabIcon },
 42→  { tool: TOOLS.ROOM, label: 'Room', shortcut: 'R', Icon: RoomIcon },
 43→  { tool: TOOLS.DOOR, label: 'Door', shortcut: 'D', Icon: DoorIcon },
 44→  { tool: TOOLS.WINDOW, label: 'Window', shortcut: 'N', Icon: WindowIcon },
 45→  { tool: TOOLS.COLUMN, label: 'Column', shortcut: 'C', Icon: ColumnIcon },
 46→  { tool: TOOLS.LANDING, label: 'Landing', shortcut: 'L', Icon: LandingIcon },
 47→  { tool: TOOLS.RAILING, label: 'Railing', shortcut: 'H', Icon: RailingIcon },
 48→];
 49→
 50→export default function Toolbar({
 51→  onNew,
 52→  onSave,
 53→  onLoad,
 54→  isSidebarCollapsed,
 55→  isPropertiesCollapsed,
 56→  onToggleSidebar,
 57→  onToggleProperties,
 58→}) {
 59→  const {
 60→    activeTool,
 61→    showGrid,
 62→    snapEnabled,
 63→    activeFloorId,
 64→    viewMode,
 65→    workspaceMode,
 66→    modelTarget,
 67→    toolState,
 68→    activePhaseId,
 69→    selectedId,
 70→    selectedType,
 71→    dispatch: editorDispatch,
 72→  } = useEditor();
 73→  const { project, isDirty, canUndo, canRedo, dispatch } = useProject();
 74→  const {
 75→    canCopySelection,
 76→    canPaste,
 77→    copySelection,
 78→    cutSelection,
 79→    beginPaste,
 80→  } = usePlanClipboardController();
 81→  const isPlanView = workspaceMode === 'model' && viewMode === 'plan' && modelTarget === 'floor';
 82→  const isRoofPlanView = workspaceMode === 'model' && viewMode === 'plan' && modelTarget === 'roof';
 83→  const isTrussPlanView = workspaceMode === 'model' && viewMode === 'plan' && modelTarget === 'truss';
 84→
 85→  const fixtureItems = [
 86→    { fixtureType: FIXTURE_TYPES.KITCHEN_TOP, label: 'Kitchen Top', Icon: KitchenTopIcon },
 87→    { fixtureType: FIXTURE_TYPES.TOILET, label: 'Toilet', Icon: ToiletIcon },
 88→    { fixtureType: FIXTURE_TYPES.LAVATORY, label: 'Lavatory', Icon: LavatoryIcon },
 89→    { fixtureType: FIXTURE_TYPES.TABLE, label: 'Table', Icon: TableIcon },
 90→    { fixtureType: FIXTURE_TYPES.TV, label: 'TV', Icon: TVIcon },
 91→    { fixtureType: FIXTURE_TYPES.SOFA, label: 'Sofa', Icon: SofaIcon },
 92→    { fixtureType: FIXTURE_TYPES.BED, label: 'Bed', Icon: BedIcon },
 93→  ];
 94→
 95→  const setTool = (tool) => {
 96→    editorDispatch({ type: 'SET_TOOL', tool });
 97→
 98→    if (tool !== TOOLS.TRUSS_DRAW || modelTarget !== 'truss') return;
 99→
100→    const targetTrussSystem = selectedType === 'trussSystem'
101→      ? (project.trussSystems || []).find((entry) => entry.id === selectedId) || null
102→      : selectedType === 'trussInstance'
103→        ? (project.trussSystems || []).find((entry) => (
104→            (entry.trussInstances || []).some((trussInstance) => trussInstance.id === selectedId)
105→          )) || null
106→        : null;
107→    const selectedTrussInstance = selectedType === 'trussInstance' && targetTrussSystem
108→      ? (targetTrussSystem.trussInstances || []).find((entry) => entry.id === selectedId) || null
109→      : null;
110→    const lastSystemInstance = targetTrussSystem && (targetTrussSystem.trussInstances || []).length
111→      ? targetTrussSystem.trussInstances[targetTrussSystem.trussInstances.length - 1]
112→      : null;
113→
114→    editorDispatch({
115→      type: 'UPDATE_TOOL_STATE',
116→      payload: {
117→        targetTrussSystemId: targetTrussSystem?.id || null,
118→        trussTypeId: selectedTrussInstance?.trussTypeId
119→          || lastSystemInstance?.trussTypeId
120→          || null,
121→        trussMaterial: selectedTrussInstance?.material
122→          || lastSystemInstance?.material
123→          || null,
124→      },
125→    });
126→  };
127→  const roofToolItems = [
128→    { tool: TOOLS.SELECT, label: 'Select', shortcut: 'V', Icon: SelectIcon },
129→    { tool: TOOLS.ROOF_PARAPET, label: 'Parapet', shortcut: 'P', Icon: ParapetIcon },
130→    { tool: TOOLS.ROOF_DRAIN, label: 'Drain', shortcut: 'G', Icon: DrainIcon },
131→    { tool: TOOLS.ROOF_OPENING, label: 'Opening', shortcut: 'O', Icon: OpeningIcon },
132→  ];
133→  const trussToolItems = [
134→    { tool: TOOLS.SELECT, label: 'Select', shortcut: 'V', Icon: SelectIcon },
135→    { tool: TOOLS.TRUSS_DRAW, label: 'Draw Truss', shortcut: 'T', Icon: TrussDrawIcon },
136→  ];
137→  const currentViewModes = modelTarget === 'truss'
138→    ? [
139→        { key: 'plan', label: 'Plan', viewMode: 'plan' },
140→        { key: 'detail', label: 'Detail', viewMode: 'truss_detail' },
141→        { key: 'section', label: 'Section', viewMode: 'section_view' },
142→      ]
143→    : viewModes;
144→
145→  const handleUndo = useCallback(() => {
146→    if (!canUndo) return;
147→    dispatch({ type: 'UNDO' });
148→    editorDispatch({ type: 'DESELECT' });
149→    editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Undid last change.' });
150→  }, [canUndo, dispatch, editorDispatch]);
151→
152→  const handleRedo = useCallback(() => {
153→    if (!canRedo) return;
154→    dispatch({ type: 'REDO' });
155→    editorDispatch({ type: 'DESELECT' });
156→    editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Redid last change.' });
157→  }, [canRedo, dispatch, editorDispatch]);
158→
159→  const handleDetectRooms = () => {
160→    const floor = project.floors.find(f => f.id === activeFloorId);
161→    if (!floor || floor.walls.length < 3) {
162→      editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Draw at least 3 walls first.' });
163→      return;
164→    }
165→    const detected = detectRooms(floor.walls, floor.columns || []);
166→    const rooms = detected.map((d, i) => {
167→      const room = createRoom(`Room ${i + 1}`, d.points);
168→      room.phaseId = activePhaseId || null;
169→      return room;
170→    });
171→    dispatch({ type: 'ROOMS_SET', floorId: activeFloorId, rooms });
172→    editorDispatch({ type: 'DESELECT' });
173→    editorDispatch({
174→      type: 'SET_STATUS_MESSAGE',
175→      message: rooms.length ? `Detected ${rooms.length} room${rooms.length === 1 ? '' : 's'}.` : 'No enclosed rooms detected.',
176→    });
177→  };
178→
179→  useEffect(() => {
180→    const handleKeyDown = (e) => {
181→      if (!(e.ctrlKey || e.metaKey)) return;
182→      if (isTypingTarget(e.target)) return;
183→
184→      const key = e.key.toLowerCase();
185→      const isRedo = (key === 'z' && e.shiftKey) || key === 'y';
186→      const isUndo = key === 'z' && !e.shiftKey;
187→      if (!isUndo && !isRedo) return;
188→
189→      e.preventDefault();
190→      if (isRedo) {
191→        handleRedo();
192→        return;
193→      }
194→      handleUndo();
195→    };
196→
197→    window.addEventListener('keydown', handleKeyDown);
198→    return () => window.removeEventListener('keydown', handleKeyDown);
199→  }, [handleRedo, handleUndo]);
200→
201→  const activeViewKey = workspaceMode === 'sheet' ? 'sheets' :
202→    currentViewModes.find(v => v.viewMode === viewMode)?.key || 'plan';
203→
204→  return (
205→    <div className={styles.toolbar}>
206→      {/* File & clipboard actions */}
207→      <div className={styles.group}>
208→        <Tooltip label="New Project">
209→          <button className={styles.btn} onClick={onNew} aria-label="New Project">
210→            <NewIcon className={styles.icon} />
211→          </button>
212→        </Tooltip>
213→        <Tooltip label="Undo" shortcut="Ctrl+Z">
214→          <button
215→            className={styles.btn}
216→            onClick={handleUndo}
217→            disabled={!canUndo}
218→            aria-label="Undo"
219→          >
220→            <UndoIcon className={styles.icon} />
221→          </button>
222→        </Tooltip>
223→        <Tooltip label="Redo" shortcut="Ctrl+Shift+Z">
224→          <button
225→            className={styles.btn}
226→            onClick={handleRedo}
227→            disabled={!canRedo}
228→            aria-label="Redo"
229→          >
230→            <RedoIcon className={styles.icon} />
231→          </button>
232→        </Tooltip>
233→        <Tooltip label="Save" shortcut="Ctrl+S">
234→          <button
235→            className={styles.saveBtn}
236→            onClick={onSave}
237→            data-dirty={isDirty}
238→            aria-label="Save"
239→          >
240→            <SaveIcon className={styles.icon} />
241→          </button>
242→        </Tooltip>
243→        <div className={styles.divider} />
244→        <Tooltip label="Load Project">
245→          <button className={styles.btn} onClick={onLoad} aria-label="Load Project">
246→            <LoadIcon className={styles.icon} />
247→          </button>
248→        </Tooltip>
249→        <Tooltip label="Copy" shortcut="Ctrl+C">
250→          <button
251→            className={styles.btn}
252→            onClick={copySelection}
253→            disabled={!canCopySelection || modelTarget !== 'floor' || workspaceMode !== 'model'}
254→            aria-label="Copy"
255→          >
256→            <CopyIcon className={styles.icon} />
257→          </button>
258→        </Tooltip>
259→        <Tooltip label="Cut" shortcut="Ctrl+X">
260→          <button
261→            className={styles.btn}
262→            onClick={cutSelection}
263→            disabled={!canCopySelection || modelTarget !== 'floor' || workspaceMode !== 'model'}
264→            aria-label="Cut"
265→          >
266→            <CutIcon className={styles.icon} />
267→          </button>
268→        </Tooltip>
269→        <Tooltip label="Paste" shortcut="Ctrl+V">
270→          <button
271→            className={styles.btn}
272→            onClick={() => beginPaste()}
273→            disabled={!canPaste || modelTarget !== 'floor' || workspaceMode !== 'model'}
274→            aria-label="Paste"
275→          >
276→            <PasteIcon className={styles.icon} />
277→          </button>
278→        </Tooltip>
279→      </div>
280→
281→      <div className={styles.segmentedGroup}>
282→        <button
283→          className={workspaceMode === 'model' && modelTarget === 'floor' ? styles.segmentedBtnActive : styles.segmentedBtn}
284→          onClick={() => {
285→            editorDispatch({ type: 'SET_MODEL_TARGET', modelTarget: 'floor' });
286→            if (viewMode === 'truss_detail') {
287→              editorDispatch({ type: 'SET_VIEW_MODE', viewMode: 'plan' });
288→            }
289→          }}
290→        >
291→          Floor
292→        </button>
293→        <button
294→          className={workspaceMode === 'model' && modelTarget === 'roof' ? styles.segmentedBtnActive : styles.segmentedBtn}
295→          onClick={() => {
296→            editorDispatch({ type: 'SET_MODEL_TARGET', modelTarget: 'roof' });
297→            if (viewMode === 'truss_detail') {
298→              editorDispatch({ type: 'SET_VIEW_MODE', viewMode: 'plan' });
299→            }
300→          }}
301→        >
302→          Roof
303→        </button>
304→        <button
305→          className={workspaceMode === 'model' && modelTarget === 'truss' ? styles.segmentedBtnActive : styles.segmentedBtn}
306→          onClick={() => {
307→            editorDispatch({ type: 'SET_MODEL_TARGET', modelTarget: 'truss' });
308→            if (viewMode !== 'plan' && viewMode !== 'section_view' && viewMode !== 'truss_detail') {
309→              editorDispatch({ type: 'SET_VIEW_MODE', viewMode: 'plan' });
310→            }
311→          }}
312→        >
313→          Truss
314→        </button>
315→        <button
316→          className={workspaceMode === 'sheet' ? styles.segmentedBtnActive : styles.segmentedBtn}
317→          onClick={() => editorDispatch({ type: 'SET_WORKSPACE_MODE', workspaceMode: 'sheet' })}
318→        >
319→          Sheets
320→        </button>
321→      </div>
322→
323→      {/* View mode segmented control */}
324→      <div className={styles.segmentedGroup}>
325→        {currentViewModes.map(({ key, label, viewMode: vm }) => (
326→          <button
327→            key={key}
328→            className={activeViewKey === key ? styles.segmentedBtnActive : styles.segmentedBtn}
329→            onClick={() => editorDispatch({ type: 'SET_VIEW_MODE', viewMode: vm })}
330→          >
331→            {label}
332→          </button>
333→        ))}
334→      </div>
335→
336→      {/* Tool palette - inline row of icons */}
337→      <div className={styles.toolPalette}>
338→        <span className={styles.groupLabel}>Tools</span>
339→        {(modelTarget === 'roof' ? roofToolItems : (modelTarget === 'truss' ? trussToolItems : toolItems)).map(({ tool, label, shortcut, Icon }) => (
340→          <Tooltip key={tool} label={label} shortcut={shortcut}>
341→            <button
342→              className={activeTool === tool ? styles.toolPaletteBtnActive : styles.toolPaletteBtn}
343→              onClick={() => setTool(tool)}
344→              disabled={modelTarget === 'roof' ? !isRoofPlanView : (modelTarget === 'truss' ? !isTrussPlanView : !isPlanView)}
345→              aria-label={label}
346→            >
347→              <Icon className={styles.toolPaletteIcon} />
348→            </button>
349→          </Tooltip>
350→        ))}
351→      </div>
352→
353→      {/* Fixtures palette */}
354→      <div className={styles.fixturePalette}>
355→        <span className={styles.fixturePaletteLabel}>Fixtures</span>
356→        {fixtureItems.map(({ fixtureType, label, Icon }) => {
357→          const isActive = activeTool === TOOLS.FIXTURE && toolState.fixtureType === fixtureType;
358→          return (
359→            <Tooltip key={fixtureType} label={label} shortcut="F">
360→              <button
361→                className={isActive ? styles.toolPaletteBtnActive : styles.toolPaletteBtn}
362→                onClick={() => {
363→                  editorDispatch({ type: 'SET_TOOL', tool: TOOLS.FIXTURE });
364→                  editorDispatch({ type: 'UPDATE_TOOL_STATE', payload: { fixtureType, previewRotation: 0 } });
365→                }}
366→                disabled={!isPlanView}
367→                aria-label={label}
368→              >
